content.text:
type RunStartedEvent {
  runId: ID!
  conversationId: ID!
  startedAt: DateTime!
}

type TextDeltaEvent {
  runId: ID!
  messageId: ID!
  delta: String!
  index: Int!
}

type ToolUseRequestedEvent {
  runId: ID!
  toolUseId: ID!
  toolName: String!
  input: JSON!
}

type RunCompletedEvent {
  runId: ID!
  messageId: ID!
  usage: UsageSummary!
  completedAt: DateTime!
}

type RunFailedEvent {
  runId: ID!
  error: RunError!
}

Subscription: {
  runEvents: {
    subscribe: withFilter(
      () => pubsub.asyncIterableIterator(['RUN_EVENT']),
      (payload, variables, context) => {
        return payload.runId === variables.runId
          && payload.tenantId === context.tenantId;
      }
    )
  }
}

mutation SendMessage($input: SendMessageInput!) {
  sendMessage(input: $input) {
    conversation { id }
    userMessage { id }
    run { id status }
  }
}
